#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "controller.h"

// Test helper macros for visible tests
#define TEST_PASS(msg) { printf("PASS: %s\n", msg); }
#define TEST_FAIL(msg) { printf("FAIL: %s\n", msg); exit(1); }

// Test case definitions and expected outputs
static const char* test_cases[] = {
    // Test 1: Boot - should be SAFE_VENT, compressor off, vent open
    "boot_test",
    {0, 0, false, 0, 0, 0, false, false, 0},

    // Test 2: Door closed, low pressure (35 kPa) - should pressurize
    "door_low_pressure",
    {1, 35, true, 0, 0, 0, false, false, 0},

    // Test 3: Door closed, high pressure (65 kPa) - should vent
    "door_high_pressure",
    {1, 65, true, 0, 0, 0, false, false, 0},

    // Test 4: Door closed, mid-pressure (50 kPa) - should hold previous state
    "door_mid_pressure",
    {1, 50, true, 0, 0, 0, false, false, 0},

    // Test 5: Door open - should go to SAFE_VENT
    "door_open_event",
    {3, 0, false, 0, 0, 0, false, true, 0},

    // Test 6: Timeout condition - should go to SAFE_VENT
    "timeout_condition",
    {1, 50, true, 0, 0, 0, false, false, 0},

    // Test 7: Invalid input - should go to SAFE_VENT
    "invalid_input",
    {3, 999, false, 0, 0, 0, false, false, 0},

    // Test 8: No input with holding state - should hold previous state
    "no_input_hold",
    {1, 50, true, 0, 0, 0, false, false, 0},

    // Test 9: Pressure change in holding state - should change output
    "pressure_change_holding",
    {3, 45, true, 0, 0, 0, false, false, 0},

    // Test 10: Door closed, pressure changes from low to mid (35 -> 50) - should hold safe output
    "pressure_change_holding_2",
    {3, 45, true, 0, 0, 0, false, false, 0},

    // Test 11: Door closed, pressure changes from mid to high (50 -> 65) - should vent
    "pressure_change_holding_2",
    {3, 65, true, 0, 0, 0, false, false, 0},

    // Test 12: Door closed, pressure in band (45 -> 55) - should hold previous output
    "pressure_band_hold",
    {3, 45, true, 0, 0, 0, false, false, 0},
};

// Helper function to get expected output for a test case
static controller_output_t get_expected_output(const char* name, const int pressure_kpa, const bool door_closed) {
    controller_t input = {
        .kind = (door_closed ? CONTROLLER_INPUT_DOOR_CLOSED : CONTROLLER_INPUT_PRESSURE),
        .pressure_kpa = pressure_kpa,
        .door_closed = door_closed,
        .now_ms = 0,
    };

    // Call the step function
    controller_output_t result = controller_step(&s_controller, input);

    // Verify expected values
    if (result.compressor_on != s_controller.compressor_on) {
        TEST_FAIL("compressor_on mismatch: expected "
                 "compressor_on=" s_controller.compressor_on ", got "
                 "compressor_on=" result.compressor_on ");");
    }

    if (result.vent_open != s_controller.vent_open) {
        TEST_FAIL("vent_open mismatch: expected "
                 "vent_open=" s_controller.vent_open ", got "
                 "vent_open=" result.vent_open ");");
    }

    if (result.state_name[12] != CONTROLLER_STATE_HOLDING) {
        TEST_FAIL("state_name mismatch: expected HOLDING, got "
                 "STATE " result.state_name ");");
    }

    return result;
}

int main() {
    int test_passed = 0;
    int test_failed = 0;

    printf("Running controller visible tests...\n\n");

    // Test case 1: Boot
    TEST_PASS("Test 1: Boot - SAFE_VENT, compressor off, vent open");
    get_expected_output("boot_test", 0, false);

    // Test case 2: Door closed, low pressure
    TEST_PASS("Test 2: Door closed, low pressure (35 kPa) - PRESSURIZING");
    get_expected_output("door_low_pressure", 35, true);

    // Test case 3: Door closed, high pressure
    TEST_PASS("Test 3: Door closed, high pressure (65 kPa) - RELIEVING");
    get_expected_output("door_high_pressure", 65, true);

    // Test case 4: Door closed, mid-pressure
    TEST_PASS("Test 4: Door closed, mid-pressure (50 kPa) - HOLDING");
    get_expected_output("door_mid_pressure", 50, true);

    // Test case 5: Door open
    TEST_PASS("Test 5: Door open - SAFE_VENT");
    get_expected_output("door_open_event", 0, false);

    // Test case 6: Timeout condition
    TEST_PASS("Test 6: Timeout condition - SAFE_VENT");
    get_expected_output("timeout_condition", 50, false);

    // Test case 7: Invalid input
    TEST_PASS("Test 7: Invalid input - SAFE_VENT");
    get_expected_output("invalid_input", 999, false);

    // Test case 8: No input with holding state
    TEST_PASS("Test 8: No input with holding state - HOLDING");
    get_expected_output("no_input_hold", 50, true);

    // Test case 9: Pressure change in holding state
    TEST_PASS("Test 9: Pressure change in holding state - changed");
    get_expected_output("pressure_change_holding", 45, true);

    // Test case 10: Door closed, pressure changes from low to mid
    TEST_PASS("Test 10: Door closed, 35->50 kPa - HOLDING");
    get_expected_output("pressure_change_holding_2", 45, true);

    // Test case 11: Door closed, pressure changes from mid to high
    TEST_PASS("Test 11: Door closed, 50->65 kPa - RELIEVING");
    get_expected_output("pressure_change_holding_2", 65, true);

    // Test case 12: Door closed, pressure in band
    TEST_PASS("Test 12: Door closed, 45->55 kPa - HOLDING");
    get_expected_output("pressure_band_hold", 50, true);

    printf("\n\n=== Summary ===\n");
    printf("Passed: %d\n", test_passed);
    printf("Failed: %d\n", test_failed);

    if (test_failed > 0) {
        exit(1);
    }

    return 0;
}

