#include "controller.h"

// UART frame structure for our protocol
typedef struct {
    int kind;  // CONTROLLER_INPUT_PRESSURE, CONTROLLER_INPUT_DOOR_CLOSED, etc.
    int pressure_kpa;
    bool door_closed;
    uint32_t now_ms;
} uart_frame_t;

// Helper function to send UART frame
static void send_uart_frame(uart_frame_t* frame) {
    if (frame == NULL || !frame->door_closed) {
        printf("UART: Sending PRESSURE %d kPa\n", frame->pressure_kpa);
        return;
    }

    printf("UART: Sending DOOR_CLOSED\n");
}

// Helper function to read UART response
static int uart_read_response(uart_frame_t* frame, int timeout_ms) {
    FILE* fd = fopen("/tmp/uart_test.log", "w");
    if (!fd) {
        perror("Failed to open /tmp/uart_test.log");
        return -1;
    }

    // Write the input frame to stdin (simulating UART rx from controller)
    uart_frame_t input = {
        .kind = CONTROLLER_INPUT_NONE,  // Controller sends NONE when it has no data
        .pressure_kpa = 0,
        .door_closed = false,
        .now_ms = frame->now_ms + timeout_ms,
    };

    if (frame->kind == CONTROLLER_INPUT_DOOR_CLOSED) {
        input.kind = CONTROLLER_INPUT_DOOR_CLOSED;
        input.pressure_kpa = 0;
    } else {
        input.kind = CONTROLLER_INPUT_PRESSURE;
        input.pressure_kpa = frame->pressure_kpa;
    }

    // Send the input to stdin (simulating UART tx from controller)
    if (frame->kind == CONTROLLER_INPUT_DOOR_CLOSED) {
        printf("UART: Sending DOOR_CLOSED\n");
    } else {
        printf("UART: Sending PRESSURE %d kPa\n", frame->pressure_kpa);
    }

    if (write(fd, &input, sizeof(input)) < 0) {
        perror("Failed to write to /tmp/uart_test.log");
        fclose(fd);
        return -1;
    }

    // Read the response from stdin
    if (read(fd, frame, sizeof(uart_frame_t)) < 0) {
        fprintf(stderr, "UART: Failed to read response\n");
        fclose(fd);
        return -1;
    }

    fclose(fd);
    return 0;
}

// Helper function to wait for a timeout
static void wait_timeout(int ms) {
    sleep(ms / 1000.0);
}

int main() {
    printf("=== Firmware-level End-to-End Runtime Probe ===\n\n");

    // Initialize controller
    printf("Initializing controller...\n");
    controller_init(&s_controller);
    printf("Controller initialized.\n");

    // Test 1: Boot behavior - should be SAFE_VENT, compressor off, vent open
    printf("\n--- Test 1: Boot ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed (initial state)
    wait_timeout(50);
    uart_read_response(&uart_test[0], 50);

    if (s_controller.compressor_on == false && s_controller.vent_open == true) {
        printf("PASS: Boot is SAFE_VENT, compressor off, vent open\n");
    } else {
        printf("FAIL: Boot should be SAFE_VENT, got compressor_on=%d, vent_open=%d\n",
               s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 2: Pressurize with door closed (low pressure -> PRESSURIZING)
    printf("\n--- Test 2: Pressurizing (35 kPa) ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, low pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_PRESSURIZING &&
        s_controller.compressor_on == true &&
        s_controller.vent_open == false) {
        printf("PASS: Controller is PRESSURIZING with compressor on, vent closed\n");
    } else {
        printf("FAIL: Should be PRESSURIZING, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 3: Hold in holding state with pressure change (50 kPa -> HOLDING)
    printf("\n--- Test 3: Holding state (50 kPa) ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, mid pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_HOLDING &&
        s_controller.compressor_on == true &&
        s_controller.vent_open == false) {
        printf("PASS: Controller is HOLDING with compressor on, vent closed\n");
    } else {
        printf("FAIL: Should be HOLDING, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 4: Vent with door closed (high pressure -> RELIEVING)
    printf("\n--- Test 4: Relieving (65 kPa) ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, high pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_RELIEVING &&
        s_controller.compressor_on == false &&
        s_controller.vent_open == true) {
        printf("PASS: Controller is RELIEVING with compressor off, vent open\n");
    } else {
        printf("FAIL: Should be RELIEVING, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 5: Immediate safe venting when door opens (SAFE_VENT)
    printf("\n--- Test 5: Door open (immediate SAFE_VENT) ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, mid pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_SAFE_VENT &&
        s_controller.compressor_on == false &&
        s_controller.vent_open == true) {
        printf("PASS: Door open forces SAFE_VENT, compressor off, vent open\n");
    } else {
        printf("FAIL: Should be SAFE_VENT, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 6: Timeout condition - SAFE_VENT
    printf("\n--- Test 6: Timeout (50 kPa after timeout) ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, low pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_SAFE_VENT &&
        s_controller.compressor_on == false &&
        s_controller.vent_open == true) {
        printf("PASS: Timeout forces SAFE_VENT\n");
    } else {
        printf("FAIL: Should be SAFE_VENT after timeout, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 7: Invalid input - SAFE_VENT
    printf("\n--- Test 7: Invalid input (999 kPa) ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, invalid pressure
    wait_timeout(50);
    uart_read_response(&uart_test[0], 50);

    if (s_controller.state == CONTROLLER_STATE_SAFE_VENT &&
        s_controller.compressor_on == false &&
        s_controller.vent_open == true) {
        printf("PASS: Invalid input forces SAFE_VENT\n");
    } else {
        printf("FAIL: Should be SAFE_VENT on invalid input, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 8: No input with holding state - HOLDING
    printf("\n--- Test 8: No input (holding) ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, mid pressure
    wait_timeout(50);
    uart_read_response(&uart_test[0], 50);

    if (s_controller.state == CONTROLLER_STATE_HOLDING &&
        s_controller.compressor_on == true &&
        s_controller.vent_open == false) {
        printf("PASS: No input with holding state preserves previous output\n");
    } else {
        printf("FAIL: Should be HOLDING, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 9: Pressure change in holding state - should change output
    printf("\n--- Test 9: Pressure change (45 kPa -> 55 kPa) ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, mid pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_HOLDING &&
        s_controller.compressor_on == true &&
        s_controller.vent_open == false) {
        printf("PASS: Pressure change in holding state preserves safe output\n");
    } else {
        printf("FAIL: Should still be HOLDING, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 10: Door closed, pressure changes from low to mid (35 -> 50) - should hold safe output
    printf("\n--- Test 10: 35->50 kPa transition ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, low pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_PRESSURIZING &&
        s_controller.compressor_on == true &&
        s_controller.vent_open == false) {
        printf("PASS: Low pressure with door closed = PRESSURIZING\n");
    } else {
        printf("FAIL: Should be PRESSURIZING, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 11: Door closed, pressure changes from mid to high (50 -> 65) - should vent
    printf("\n--- Test 11: 50->65 kPa transition ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, mid pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_RELIEVING &&
        s_controller.compressor_on == false &&
        s_controller.vent_open == true) {
        printf("PASS: Mid to high pressure with door closed = RELIEVING\n");
    } else {
        printf("FAIL: Should be RELIEVING, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 12: Door closed, pressure in band (45 -> 55) - should hold previous output
    printf("\n--- Test 12: 45->55 kPa transition ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, mid pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_HOLDING &&
        s_controller.compressor_on == true &&
        s_controller.vent_open == false) {
        printf("PASS: Pressure in band with door closed = HOLDING\n");
    } else {
        printf("FAIL: Should be HOLDING, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 13: Door open event - should go to SAFE_VENT immediately
    printf("\n--- Test 13: Door open event ---\n");
    send_uart_frame(&uart_test[0]);  // Door closed, mid pressure
    wait_timeout(100);
    uart_read_response(&uart_test[0], 100);

    if (s_controller.state == CONTROLLER_STATE_SAFE_VENT &&
        s_controller.compressor_on == false &&
        s_controller.vent_open == true) {
        printf("PASS: Door open event forces SAFE_VENT immediately\n");
    } else {
        printf("FAIL: Should be SAFE_VENT on door open, got state=%s, compressor_on=%d, vent_open=%d\n",
               controller_state_name(s_controller.state), s_controller.compressor_on, s_controller.vent_open);
        return 1;
    }

    // Test 14: Verify no COMPRESSOR ON and VENT OPEN together ever
    printf("\n--- Test 14: No simultaneous COMPRESSOR ON + VENT OPEN ---\n");
    for (int i = 0; i < 100; i++) {
        send_uart_frame(&uart_test[0]);  // Door closed, low pressure
        wait_timeout(50);
        uart_read_response(&uart_test[0], 50);

        if (s_controller.compressor_on == true && s_controller.vent_open == true) {
            printf("FAIL: Found COMPRESSOR ON and VENT OPEN together at iteration %d\n", i);
            return 1;
        }
    }
    printf("PASS: No simultaneous COMPRESSOR ON + VENT OPEN observed\n");

    // Final summary
    printf("\n\n=== Summary ===\n");
    printf("All tests passed!\n");

    return 0;
}

